exemplos.python:
idade = int(input("Idade do candidato: "))

if idade >= 18:
    print("Pode votar.")
else:
    print("Ainda não pode votar.")

nota = float(input("Nota final (0-10): "))

if nota >= 7.0:
    print(f"Nota {nota:.1f}: APROVADO")
else:
    print(f"Nota {nota:.1f}: REPROVADO")

nome = input("Nome do paciente: ")
temperatura = float(input("Temperatura (°C): "))

if temperatura <= 37.5:
    print(f"{nome}: triagem NORMAL")
else:
    print(f"{nome}: triagem com FEBRE")
    if temperatura >= 39.0:
        print("  -> encaminhar para atendimento prioritário")
